// Janela móvel de 7 dias, uma linha por categoria de agenda.
//
// Por que 7 dias e não 1: o status muda depois. Um horário que hoje é AGENDADO
// vira ATENDIDO ou DESMARCADO amanhã, e a API do Doutor Hérnia não guarda esse
// histórico. Reprocessar os últimos 7 dias todo dia corrige as linhas antigas
// (o append-or-update casa por idSchedule) sem estourar as 100 linhas por página.
//
// Por que uma requisição por categoria: a resposta de /schedules/search NÃO traz
// o campo de categoria. A única forma de saber se é avaliação ou sessão é pedir
// filtrado por idCategory e carimbar a resposta.

const hoje = new Date();
const iso = (d) => d.toISOString().slice(0, 10);
const endDate = iso(hoje);
const initialDate = iso(new Date(hoje.getTime() - 7 * 86400000));

const categorias = [
  { idCategory: 1, categoria: 'AVALIACAO' },
  { idCategory: 2, categoria: 'SESSAO' },
  { idCategory: 3, categoria: 'RETORNO' },
];

return categorias.map((c) => ({
  json: { ...c, initialDate, endDate },
}));

// Achata as respostas (uma por categoria) em uma linha por agendamento.
//
// Converte dateAttendance de UTC para o horário de Imperatriz (UTC-3). Isso NÃO é
// cosmético: existem consultas às 00:15/00:30 UTC que são 21h15/21h30 do dia
// ANTERIOR no local. Agrupar pelo UTC cru joga a linha no dia errado.

const LOCAL_OFFSET_H = -3; // Imperatriz/MA — sem horário de verão desde 2019
const capturadoEm = new Date().toISOString();
const saida = [];
const pedidos = $('Janela de 7 dias').all();

items.forEach((item, i) => {
  const categoria = pedidos[i]?.json?.categoria ?? 'DESCONHECIDA';
  const pagina = item.json?.data;
  const linhas = pagina?.data ?? [];

  if ((pagina?.totalPages ?? 1) > 1) {
    // Guarda-rail: 7 dias cabem em 100 linhas hoje (~350 agendamentos/mês). Se a
    // unidade crescer, isso passa a truncar em silêncio — melhor falhar alto.
    throw new Error(
      `Categoria ${categoria}: ${pagina.total} agendamentos em ${pagina.totalPages} páginas. ` +
      `Reduza a janela ou implemente paginação.`,
    );
  }

  for (const r of linhas) {
    const utc = new Date(r.dateAttendance);
    const local = new Date(utc.getTime() + LOCAL_OFFSET_H * 3600000);

    saida.push({
      json: {
        idSchedule: r.idSchedule,
        idTreatment: r.idTreatment ?? '',
        categoria,
        paciente: (r.clientName ?? '').trim(),
        dia: local.toISOString().slice(0, 10),
        hora: local.toISOString().slice(11, 16),
        dataHoraUtc: r.dateAttendance,
        idStatus: r.idStatus,
        status: r.statusName,
        compareceu: r.idStatus === 42 ? 'SIM' : r.idStatus === 40 ? 'NAO' : '',
        profissional: (r.physicalTherapist ?? '').trim(),
        modificadoEm: r.modified ?? '',
        modificadoPor: r.modifiedBy ?? '',
        capturadoEm,
      },
    });
  }
});

return saida;
